import React from 'react';
import { createRoot } from 'react-dom/client';
import './style.css';

function App() {
  return <main><h1>Codeleon React</h1><p>Build something sharp.</p></main>;
}

createRoot(document.getElementById('root')).render(<App />);

body { margin: 0; font-family: Inter, system-ui, sans-serif; background: #09090b; color: #f4f4f5; }
main { min-height: 100vh; display: grid; place-items: center; text-align: center; }
h1 { color: #22d3ee; }
